code = """import json
import pandas as pd
import re
import numpy as np

# Load clinical data
clinical_file_path = locals()['var_function-call-6882553506767091265']
with open(clinical_file_path, 'r') as f:
    clinical_data = json.load(f)

# Load molecular data
molecular_file_path = locals()['var_function-call-18230223163438888299']
with open(molecular_file_path, 'r') as f:
    molecular_data = json.load(f)

# Process clinical data
clinical_records = []
barcode_pattern = re.compile(r'(TCGA-[A-Z0-9]{2}-[A-Z0-9]{4})')

for entry in clinical_data:
    desc = entry.get('Patient_description', '')
    histology = entry.get('histological_type', '')
    
    # Extract barcode
    match = barcode_pattern.search(desc)
    if match:
        barcode = match.group(1)
        clinical_records.append({
            'ParticipantBarcode': barcode,
            'histological_type': histology
        })

df_clinical = pd.DataFrame(clinical_records)

# Filter histology
# Exclude if enclosed in square brackets
# Also exclude "None" or null if necessary, though problem only mentions brackets
def is_valid_histology(h):
    if not h:
        return False
    if h.startswith('[') and h.endswith(']'):
        return False
    return True

df_clinical = df_clinical[df_clinical['histological_type'].apply(is_valid_histology)]

# Process molecular data
df_molecular = pd.DataFrame(molecular_data)
# Ensure numeric
df_molecular['normalized_count'] = pd.to_numeric(df_molecular['normalized_count'], errors='coerce')
df_molecular = df_molecular.dropna(subset=['normalized_count'])

# Merge
merged_df = pd.merge(df_clinical, df_molecular, on='ParticipantBarcode', how='inner')

# Compute log10(normalized_count + 1)
merged_df['log_expression'] = np.log10(merged_df['normalized_count'] + 1)

# Group by histology and compute average
result_df = merged_df.groupby('histological_type')['log_expression'].mean().reset_index()

# Format results
# "Report the final average values with at least four decimal places of precision."
# I will output a dictionary {histology: average}
results = {}
for index, row in result_df.iterrows():
    results[row['histological_type']] = round(row['log_expression'], 4)

print("__RESULT__:")
print(json.dumps(results))"""

